var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님, 저 모습. 관리국 데이터베이스에서 본 적 있습니다.","JPN":"中将。あの姿、管理局のデータベースで見たことがあります。","ENG":"Lieutenant General, I've seen that form in the Administration database.","TWN":"中將，那個樣子，我在管理局資料庫看過。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 아무래도 데몬 타입 침식체와 언데드 타입 침식체인 듯싶군.","JPN":"ああ、どうやらデーモンタイプの侵食体と、アンデッドタイプの侵食体のようだな。","ENG":"Right. Looks like Demon-type and Undead-type C.O.s.","TWN":"沒錯，總覺得應該是惡魔型侵蝕體和不死型侵蝕體。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"설마… 3종과 4종 침식체가 저 정도 군집을 이룰 줄이야.","JPN":"まさか……第3種と第4種があれほどの群れをなすとは。","ENG":"I never thought... Category 3 and Category 4 C.O.s would swarm in numbers like that.","TWN":"沒想到…3類和4類侵蝕體會形成那樣的群集。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"왕의 행보를 어지럽힌 실패자들을 감히 우리와 비하는가.","JPN":"王の行く手を妨げた失敗作と我々を比較するか。","ENG":"You dare liken the failures who sullied the queen's march to us?","TWN":"擾亂魔王步伐的失敗者竟敢與我們相提並論？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L11_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"비록 천대한 미물의 망언일지 언정, 실로 불경스럽기 짝이 없도다.","JPN":"下賎な微物の妄言とはいえ、実に不敬極まりない。","ENG":"Even if it's the insolent babble of base vermin, it is blasphemy all the same.","TWN":"儘管是卑賤又渺小的人類妄言，其實極為不敬。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"들었어요, 린 시엔 씨? 저기 있는 침식체. 3종이랑 4종이래요.","JPN":"聞きました、リン・シエンさん？　あの侵食体、第3種と第4種ですって。","ENG":"You heard that, Lin Xien? Those are Category 3 and Category 4 C.O.s.","TWN":"聽到了嗎？林·西恩？那裡的侵蝕體是3類和4類。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"저흰 이제 뭘 할 수 있죠?","JPN":"秋たちに何ができるんでしょぅ？","ENG":"What can we even do now?","TWN":"我們現在能做什麼？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗훗. 피로 피를 씻는 항쟁에서 총은 단 한가지 방법만을 알고 있다네, 친구.","JPN":"ふっふっふっ。血で血を洗う抗争で、銃はたった1つのやり方しか知らないのだ、友よ。","ENG":"Hehehe. In a struggle where blood washes blood, a gun knows but one way, my friend.","TWN":"呵呵呵，在用血將血洗淨的抗爭中，槍只知道一種方法，朋友。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"다만 오늘은 몸상태가 나쁘니… 조, 좋은 승부를 내기 힘들겠어.","JPN":"ただ、今日は体調が悪く……い、いい勝負は難しそうだな。","ENG":"Only... I'm not in top shape today. A g-good duel would be hard to promise.","TWN":"但我今天身體狀況很差…很、很難決出一場好的勝負。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"걱정 마세요. 전달된 내용에 따르면 사도는 현실세계에서 제힘을 낼 수 없는 걸요.","JPN":"心配いりません。伝え聞いた内容によると、使徒は現実世界では本来の力を発揮できません。","ENG":"Don't worry. Per the brief, Apostles can't exert their full power in the Normalside.","TWN":"別擔心，根據接獲的內容，使徒在現實世界中無法使出自己的力量。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그 점을 고려하면… 여러분이 생각하시는 것만큼 큰 위협은 아닐 거예요.","JPN":"それを考えると……皆さんが心配されているほどの脅威ではないはずです。","ENG":"With that in mind... they're not as big a threat as you think.","TWN":"考量到這一點…構成的威脅應該不會像各位所想的那麼大。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"확실히, 앞서 마녀의 그림자들을 단죄하기 위한 권능을 휘둘렀으니.","JPN":"確かに、先に魔女のシャドウらを断罪するための権能を振るい……","ENG":"True, I brandished the authority to condemn the witch's Shadows earlier.","TWN":"的確，之前為了替魔女的暗影定罪，已經動用權能。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"이곳의 자매들이 왕께서 하사하신 이름을 잃은 것은 부인할 수 없는 사실이도다.","JPN":"ここの姉妹たちが王に授けられた名を失ったことは否定できぬ事実。","ENG":"I cannot deny the sisters here lost the name our queen bestowed.","TWN":"這裡的姐妹們失去了魔王賜予的名字，這是不可否認的事實。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"허나 불경스러운 장치가 끝을 고함에 대균열의 뿌리가 제 위세를 되찾은 지금…….","JPN":"しかし不敬な装置が動きを止め、大亀裂の根が本来の勢いを取り戻した今……","ENG":"Yet now that the profane device has fallen silent and the Grand Dimension Crevice's roots reclaim their might...","TWN":"但不敬的裝置宣告結束，大峽谷根部現在重新找回我的威勢……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_IDLE"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NERVIA_CORRUPT_NULL_APOSTLE","text":{"KOREA":"네놈들이 밟고 있는 땅을, 어찌 묘혈이라 부르지 않겠느냐.","JPN":"貴様らが足をつけている地は、もはや墓穴も同然だ。","ENG":"How could I call the ground beneath your feet anything but your grave plot?","TWN":"你們這些傢伙踩著的土地，豈不就稱為墓穴嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NERVIA_CORRUPT_NULL_APOSTLE","face":"UNIT_SERIOUS"},"R":{"char_id":"MINISTRA_CORRUPT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"바, 방금 뭔가 번쩍하고 움직였는데…?","JPN":"い、今何かが光って、動いたけど……？","ENG":"S-something just flashed and moved...?","TWN":"剛、剛才是什麼一閃一閃動了一下…？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"민서 양, 괜찮아요?","JPN":"ヒミコさん、大丈夫ですか？","ENG":"Minseo, are you okay?","TWN":"旼序小姐，妳還好嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"저, 저는 괜찮은데, 저를 지키려다 소령님이 다치셨어요…!!","JPN":"ヒ、ヒミコは大丈夫ですけど、ヒミコを守ろうとして少佐が怪我を……！！","ENG":"I-I'm fine, but Major got hurt protecting me...!!","TWN":"我、我沒事，少校為了保護我受傷了…！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저, 저도 괜찮아요.","JPN":"わ、私も大丈夫です。","ENG":"I-I'm all right too.","TWN":"我、我也沒事。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"이정도 상처쯤은… 금방 회복되니까요.","JPN":"この程度の傷は……すぐ治ります。","ENG":"A scratch like this... I'll recover quickly.","TWN":"這點傷…很快就會恢復。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"중장님, 아무래도…….","JPN":"中将、どうやら……","ENG":"Lieutenant General, I think–","TWN":"中將，總覺得……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SHADOW_PALACE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래. 빈틈을 노렸다고는 하나, 자네가 완전히 반응하지 못할 정도라면 우리가 알고 있는 정보와는 다른 듯싶군.","JPN":"ああ。隙を狙ったとはいえ、君ですら反応できなかったということは……我々の知っている情報とは違うようだ。","ENG":"Yes. If it slipped past you entirely even when you were watching for an opening, our intel's off.","TWN":"是啊，雖然說鑽了漏洞，但如果是妳完全反應不過來的程度，似乎跟我們知道的情報不一樣。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L43_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"저 정도 수라면… 이곳에서 항전한들 온전히 틀어막는 건 불가능하겠지.","JPN":"あの数なら……ここで抗戦を続けたところで、防ぎきれないだろう。","ENG":"With numbers like that... Holding here to block them completely is impossible.","TWN":"那樣的數量…就算在這裡抗戰，應該也無法完全阻擋。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"사도들은 우리가 맡을 테니, 프리라이더 제군은 대피하지 못한 인원들을 살펴주게.","JPN":"使徒は我々に任せて、フリーライダーの諸君はまだ避難できていない市民がいないか確認してくれ。","ENG":"We'll handle the Apostles. Free Riders, sweep for any remaining civilians and evacuate them.","TWN":"使徒由我們來負責，自由騎士就幫忙照顧那些沒有撤離的人。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"예, 예스, 맴! 명령에 따르겠습니다!","JPN":"イ、イエス、マム！　了解いたしました！","ENG":"Y-yes, ma'am! Orders received!","TWN":"是，好的！遵命！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"이것 참, 이 린 시엔님이 만전의 상태였다면 놈들과 좋은 승부가 됐을 텐데, 아쉽군.","JPN":"まったく、このリン・シエン様が万全の状態だったら、やつらといい勝負ができたはずだが……残念だ。","ENG":"A pity. Were I in peak form, those curs and I would have had a fine match.","TWN":"真是的，要是林·西恩處於萬全的狀態，應該就能和那些傢伙一決勝負，真可惜。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"헛소리 말고 가요…! 여기 있어봤자 방해만 된다고요…!!","JPN":"バカなこと言ってないでさっさと行きましょう……！　ここにいても邪魔になるだけです……！！","ENG":"Quit babbling and go...! We'll only get in the way if we stay...!!","TWN":"別胡說八道，快走吧…！待在這裡也只會妨礙而已…！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"미리 말하지, 제이나. 난 젊은 친구에게 목숨을 강요할 생각은 없네.","JPN":"先に言っておこう、ジェイナ。私は若者に命をかけろと強いるつもりはない。","ENG":"I'll say this now, Jaina. I won't force the young to stake their lives.","TWN":"話先說在前頭，婕娜，我不打算強迫年輕人送命。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"자네들의 군인정신은 존중하지만, 그게 군인다운 최후를 바란다는 건 아니거든.","JPN":"君たちの軍人精神は尊重しているが、それが軍人らしい最期に繋がるわけではないからな。","ENG":"I respect your soldiers' spirit, but that doesn't mean I want a soldier's death for you.","TWN":"雖然我尊重你們的軍人精神，但並不盼望軍人般的結局。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"……不，"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"안토노프 중장님이 저를 리플레이서 퀸이 아닌 제이나 크로펠로서 바라봐주신 순간부터.","JPN":"アントノフ中将が私をリプレイサー・クイーンではなくジェイナ・クロペルとして見てくださったその瞬間から。","ENG":"From the moment you saw me as Jaina Kropel and not Replacer Queen...","TWN":"打從安東諾夫中將把我看作婕娜·克洛佩爾，而非克隆·女皇的那一刻開始，"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 군인이 아닌 한 명의 동료로서 여러분 곁에 서자고 마음먹었습니다.","JPN":"私は軍人ではなく一人の仲間として皆さんのそばにいると決めました。","ENG":"I chose to stand beside you as a comrade, not as a soldier.","TWN":"我就下定決心不要以軍人，而是要以一個同伴的身分站在大家身邊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그러니 이건 중장님의 명령과는 상관없어요.","JPN":"ですから、これは中将のご命令とは関係ありません。","ENG":"So this isn't about your orders.","TWN":"所以這跟中將的命令無關。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 제 의지로 이곳에 남아, 중장님과 함께 싸우겠습니다.","JPN":"私は自分の意思でここに残り、中将と共に戦います。","ENG":"By my own will, I'll stay and fight with you, Lieutenant General.","TWN":"我要以自己的意志留在這裡，和中將一起戰鬥。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……역시, 자네들은 내게 과분한 후배들이야.","JPN":"……やはり君たちは、私には身に余る後輩たちだ。","ENG":"...Truly, I'm blessed with juniors I don't deserve.","TWN":"……果然，我不配有你們這樣的後輩。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그렇다면 나 역시 각오에 부응해야겠지.","JPN":"なら、私もその覚悟に応えてみせねばな。","ENG":"Then I must answer that resolve in kind.","TWN":"那麼我也不該辜負這樣的決心。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"신진대사 가속 및 생체조직 활성화율 최대치––– 테크 레벨 5.","JPN":"新陳代謝加速および生体組織活性化率、最大値───テックレベル5。","ENG":"Metabolism acceleration and bio-tissue activation to maximum––– Tech Level 5.","TWN":"加速新陳代謝與身體組織活化率最大值–––技術等級5."},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"강습형 시공가속기 <color=#ffd34c>가르강튀아</color>. 기동.","JPN":"強襲型時空加速器<color=#ffd34c>ガルガンティア</color>。起動。","ENG":"Assault time-space accelerator <color=#ffd34c>Garguantia</color>, initializing.","TWN":"強襲型時空加速器<color=#ffd34c>加爾剛迪亞</color>，啟動。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_ON","text":{"KOREA":"와라, 사도.","JPN":"来い、使徒。","ENG":"Come, Apostle.","TWN":"來吧，使徒。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_ON","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_TECH_03"},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_ON","text":{"KOREA":"네놈들의 상대가 고작 카운터 두 명이 아니라는 걸, 지금부터 보여주지.","JPN":"貴様らの相手はただのカウンター2人ではないということを、今から見せてやる。","ENG":"I'll show you that your opponents are far more than two mere Counters.","TWN":"現在開始就讓你們見識，你們這群傢伙的對手不是只有兩個制裁者。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"THEMA_SWAN_LAKE_WITHINTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_ON","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};